{
  "domain_analysis": {
    "business_context": "A logistics platform feature that automatically assigns and continuously optimizes delivery routes for drivers during their shifts, with real-time recalculation on state changes, customer proximity notifications, and vehicle-class safety enforcement. This spans multiple bounded contexts: route optimization is the orchestrator, but it depends on fleet, delivery, notification, and operations configuration contexts.",
    "bounded_context": "Route Optimization (primary), with cross-cutting dependencies on Fleet Management, Delivery Lifecycle, Customer Notification, and Operations Configuration",
    "ubiquitous_language": [
      { "term": "Shift", "definition": "A bounded work period during which a driver is active and eligible for route assignment. A shift has a start and end. Route assignment is triggered by shift start." },
      { "term": "Zone", "definition": "A geographic region that scopes both drivers and pending deliveries. A delivery belongs to exactly one zone. A driver operates within one zone per shift." },
      { "term": "Optimized Route", "definition": "An ordered sequence of delivery stops calculated to minimize cost (time, distance, or both) for all pending deliveries in a driver's zone. It is not a suggestion — it is the system's authoritative plan, though a driver may deviate." },
      { "term": "Pending Delivery", "definition": "A delivery that has been created but not yet completed, failed, or cancelled. Only pending deliveries are eligible for route inclusion." },
      { "term": "Route Recalculation", "definition": "The act of re-optimizing a driver's current route in response to a defined trigger event. Produces a new ordered stop sequence that replaces the previous one." },
      { "term": "Recalculation Trigger", "definition": "A domain event that invalidates the current route and requires recalculation. The spec defines exactly three: new delivery added to zone, delivery marked as failed, driver manual deviation." },
      { "term": "Manual Deviation", "definition": "When a driver physically departs from the system-suggested route order — e.g., skipping a stop or visiting stops out of sequence. Must be detected, not self-reported." },
      { "term": "Next 3 Stops Window", "definition": "A sliding notification boundary. When a delivery enters this window (i.e., becomes one of the next 3 planned stops), the corresponding customer is notified exactly once for that route version." },
      { "term": "Licensed Vehicle Class", "definition": "A classification of the vehicle a driver operates (e.g., motorcycle, van, truck, freight). Determines which deliveries are physically and legally permissible for that driver." },
      { "term": "Delivery Vehicle Class Requirement", "definition": "A property of a delivery that specifies the minimum or exact vehicle class needed to transport it. Derived from package dimensions, weight, or cargo type." },
      { "term": "Estimated Stop Time", "definition": "The time budget allocated per delivery stop for route calculation purposes. Defaults to 4 minutes system-wide but can be overridden at the zone level by the operations team." },
      { "term": "Zone Override", "definition": "An operations-team configuration that replaces a system default for a specific zone. Currently applies to estimated stop time; could extend to other parameters." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "When a driver starts their shift, the system MUST automatically calculate and assign an optimized route comprising all pending deliveries in their zone.",
      "invariant": false,
      "invariant_justification": "This is an automation policy. The business could decide to allow manual route creation or batch assignment instead. It is a workflow rule, not a data integrity constraint.",
      "testable_assertion": "Given a driver starts a shift in zone Z with N>0 pending deliveries, then within a defined SLA the driver has an assigned route containing all N eligible pending deliveries, ordered by the optimization algorithm."
    },
    {
      "id": "BR-2",
      "rule": "The route MUST be recalculated when a new delivery is added to the driver's zone while the shift is active.",
      "invariant": false,
      "invariant_justification": "Policy decision about when to recalculate. Operations could choose to batch new deliveries or defer recalculation to avoid driver disruption.",
      "testable_assertion": "Given a driver has an active route in zone Z, when a new pending delivery is created in zone Z, then the driver's route is recalculated to include the new delivery."
    },
    {
      "id": "BR-3",
      "rule": "The route MUST be recalculated when a delivery on the current route is marked as failed.",
      "invariant": false,
      "invariant_justification": "Policy decision. The system could alternatively just skip the failed stop without full recalculation.",
      "testable_assertion": "Given a driver has an active route containing delivery D, when D is marked as failed, then the route is recalculated excluding D."
    },
    {
      "id": "BR-4",
      "rule": "The route MUST be recalculated when the driver manually deviates from the suggested route.",
      "invariant": false,
      "invariant_justification": "Policy decision about deviation handling. The system could instead show a 'return to route' prompt without recalculating.",
      "testable_assertion": "Given a driver has an active route, when the system detects the driver has deviated from the planned stop sequence, then the route is recalculated from the driver's current position."
    },
    {
      "id": "BR-5",
      "rule": "A driver MUST NOT be assigned a delivery whose vehicle class requirement exceeds or is incompatible with the driver's licensed vehicle class.",
      "invariant": true,
      "invariant_justification": "This is a safety and legal constraint. A motorcycle physically cannot carry freight. Violating this creates liability, regulatory violations, and failed deliveries. No policy change should override this — it reflects a physical and legal reality.",
      "testable_assertion": "For every delivery D on every assigned route, D.requiredVehicleClass must be compatible with the driver's licensedVehicleClass. The system must reject any route that violates this, even if manually overridden."
    },
    {
      "id": "BR-6",
      "rule": "Customers MUST be notified when their delivery enters the 'next 3 stops' window of the active route.",
      "invariant": false,
      "invariant_justification": "The notification threshold (3 stops) is a business policy. It could be changed to 2 or 5 stops. The notification itself is a customer experience decision, not a data integrity constraint.",
      "testable_assertion": "Given a route with stops [S1..Sn] and the driver has completed stops up to Si, then customers for stops Si+1, Si+2, Si+3 have each received exactly one notification for this route version."
    },
    {
      "id": "BR-7",
      "rule": "The default estimated time per delivery stop is 4 minutes. This default CAN be overridden by the operations team on a per-zone basis.",
      "invariant": false,
      "invariant_justification": "This is explicitly a configurable policy parameter. The spec itself says it can be overridden.",
      "testable_assertion": "When calculating route timing for zone Z, if a zone override exists for estimated stop time, use the override value; otherwise use 4 minutes. The route's total estimated duration must equal the sum of travel times plus (number_of_stops × applicable_stop_time)."
    },
    {
      "id": "BR-8",
      "rule": "A route MUST only include deliveries within the driver's assigned zone.",
      "invariant": true,
      "invariant_justification": "Zone boundaries define operational jurisdiction. Cross-zone assignment breaks dispatching integrity, insurance coverage, and operational accountability. If violated, two drivers in different zones could be assigned the same delivery, or deliveries could be orphaned.",
      "testable_assertion": "For every delivery D in a driver's assigned route, D.zone must equal the driver's active shift zone."
    },
    {
      "id": "BR-9",
      "rule": "Only pending deliveries are eligible for route inclusion. Completed, failed, or cancelled deliveries MUST NOT appear on any active route.",
      "invariant": true,
      "invariant_justification": "Including non-pending deliveries corrupts the route and wastes driver time. A failed delivery re-appearing on a route is a data consistency violation.",
      "testable_assertion": "For every delivery D on an active route, D.status must equal 'pending'. No delivery with status completed, failed, or cancelled may appear in any active route's stop list."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver starts a shift in zone Z, and there are 5 pending deliveries in zone Z all compatible with the driver's vehicle class",
      "when": "The shift is activated",
      "then": "An optimized route is created containing all 5 deliveries, ordered by the optimization algorithm, and assigned to the driver"
    },
    {
      "id": "AC-2",
      "given": "A driver has an active route with 4 remaining stops in zone Z",
      "when": "A new pending delivery is created in zone Z that is compatible with the driver's vehicle class",
      "then": "The route is recalculated to include the new delivery, producing a new optimized stop order of 5 stops"
    },
    {
      "id": "AC-3",
      "given": "A driver has an active route with stops [A, B, C, D]",
      "when": "Delivery B is marked as failed",
      "then": "The route is recalculated with remaining eligible stops, and B is excluded from the new route"
    },
    {
      "id": "AC-4",
      "given": "A driver has an active route with stops [A, B, C, D] and the driver skips A and goes directly to B",
      "when": "The system detects the deviation",
      "then": "The route is recalculated from the driver's current position with all remaining pending stops"
    },
    {
      "id": "AC-5",
      "given": "A driver operates a motorcycle and zone Z has 3 pending deliveries: 2 parcels (motorcycle-compatible) and 1 freight shipment (truck-required)",
      "when": "The driver's shift starts in zone Z",
      "then": "The assigned route contains only the 2 parcel deliveries. The freight shipment is NOT included."
    },
    {
      "id": "AC-6",
      "given": "A driver has an active route [A, B, C, D, E, F] and has just completed stop A",
      "when": "The route advances so that B, C, D are the next 3 stops",
      "then": "Customers for deliveries B, C, and D each receive a proximity notification"
    },
    {
      "id": "AC-7",
      "given": "A route is recalculated and delivery X was previously in the next-3 window and already notified, but is now stop #5",
      "when": "The recalculated route is activated",
      "then": "Customer X does NOT receive a duplicate notification. When X re-enters the next-3 window on the new route, a new notification is sent referencing the updated ETA."
    },
    {
      "id": "AC-8",
      "given": "Zone Z has an operations override setting estimated stop time to 6 minutes",
      "when": "A route is calculated for a driver in zone Z with 5 stops",
      "then": "The route's estimated stop time per delivery uses 6 minutes (not the default 4), and the total route time reflects this override"
    },
    {
      "id": "AC-9",
      "given": "A driver starts a shift in zone Z and there are zero pending deliveries in zone Z",
      "when": "The shift is activated",
      "then": "The driver is assigned an empty route (or no route) and the system is ready to assign deliveries as they arrive via recalculation trigger BR-2"
    },
    {
      "id": "AC-10",
      "given": "Two drivers are active in zone Z",
      "when": "A new delivery is added to zone Z",
      "then": "The system assigns the delivery to exactly one driver's route (not both), based on optimization criteria, and recalculates that driver's route"
    }
  ],

  "edge_cases": [
    {
      "scenario": "All pending deliveries in a zone are incompatible with the driver's vehicle class",
      "expected_behavior": "The driver receives an empty route. The system should surface this to dispatch/operations as an unserviceable zone situation requiring a different vehicle class."
    },
    {
      "scenario": "A route recalculation is triggered while a previous recalculation is still in progress",
      "expected_behavior": "The system must serialize or debounce recalculation requests per driver. The latest trigger should win — no stale route should overwrite a newer one. Use a version or sequence number on routes."
    },
    {
      "scenario": "A driver deviates from the route but returns to the original sequence before the system recalculates",
      "expected_behavior": "The system should define a deviation detection threshold (distance or stop-skip based). Brief GPS drift must not trigger recalculation. Only confirmed out-of-sequence stop visits or significant geographic departure should trigger."
    },
    {
      "scenario": "A delivery is added to a zone exactly as a driver completes their last stop",
      "expected_behavior": "If the driver's shift is still active, the delivery should be assigned and a new single-stop route created. If the shift has ended, the delivery remains unassigned until the next driver starts a shift or is handled by dispatch."
    },
    {
      "scenario": "Multiple drivers in the same zone — which driver gets a new delivery?",
      "expected_behavior": "The optimization algorithm must have a multi-driver assignment strategy (e.g., nearest driver, least-loaded driver, best-fit). The spec is silent on this — it needs clarification. A delivery must never be on two drivers' routes simultaneously."
    },
    {
      "scenario": "Customer notification for stop #3 is sent, then recalculation moves that delivery to stop #7, then back to stop #2 on another recalculation",
      "expected_behavior": "The customer should receive an updated notification with a revised ETA when re-entering the window after being pushed out. Notification deduplication should be per-route-version, not per-delivery-lifetime."
    },
    {
      "scenario": "The operations team changes the zone's stop time override while drivers have active routes",
      "expected_behavior": "Existing routes should either be recalculated with the new stop time (preferred for accuracy) or the change should apply only to future route calculations. The spec does not address this — it needs a policy decision."
    },
    {
      "scenario": "Driver's shift ends while deliveries remain on the route",
      "expected_behavior": "Remaining deliveries must return to the 'unassigned pending' pool for the zone. They must not be silently dropped. This is critical for delivery SLA tracking."
    },
    {
      "scenario": "A delivery marked as failed is later retried or un-failed",
      "expected_behavior": "If the delivery returns to pending status, it should be treated as a new pending delivery in the zone, triggering recalculation per BR-2. It must not silently re-appear on a route without recalculation."
    }
  ],

  "business_impact": {
    "financial": "Route optimization directly reduces fuel costs, driver overtime, and cost-per-delivery. Correct vehicle class enforcement prevents failed delivery attempts (wasted trips). Incorrect recalculation logic could cause thrashing that increases fuel spend and delivery times, eroding margins. The 4-minute stop time default directly affects capacity planning — if too low, routes will consistently overrun; if too high, drivers are underutilized.",
    "operational": "This feature is the core dispatch engine. Bugs here cascade to every delivery. Recalculation storms (e.g., from noisy deviation detection) could overload the optimization service. Multi-driver zone assignment ambiguity could cause double-assignments or orphaned deliveries. Operations teams need reliable override controls — if zone stop-time overrides don't work correctly, ETA accuracy degrades and customer trust erodes.",
    "user": "Drivers: Route quality directly affects their workday. Constant recalculations are disruptive — recalculations should only change future stops, never retroactively re-order stops the driver is actively approaching. Customers: The 'next 3 stops' notification sets expectations. False or duplicate notifications destroy trust. Notification spam from recalculation churn is a significant CX risk.",
    "risk": "Legal/liability risk from vehicle class violations (BR-5). Operational risk from concurrent recalculation race conditions. Customer churn risk from inaccurate or spammy notifications. Data integrity risk if zone boundaries are not strictly enforced (deliveries assigned to wrong zones). The spec is silent on multi-driver zone behavior, which is a critical gap that could cause delivery duplication.",
    "stakeholders_affected": [
      { "group": "Drivers", "impact": "Core workflow change — their entire shift is now system-directed. Route quality, recalculation frequency, and deviation detection sensitivity directly affect their productivity and job satisfaction." },
      { "group": "Customers (recipients)", "impact": "Receive proximity notifications setting delivery expectations. Notification accuracy and frequency directly affect satisfaction and availability at delivery time." },
      { "group": "Operations Team", "impact": "Gain zone-level configuration control (stop time overrides). Need visibility into route assignments, recalculation events, and unserviceable zones. Responsible for monitoring and tuning." },
      { "group": "Dispatch / Fleet Management", "impact": "Must handle edge cases: unserviceable zones, shift-end handoffs, multi-driver assignment. Need dashboards showing route efficiency and unassigned delivery counts." },
      { "group": "Finance / Business Intelligence", "impact": "Route optimization metrics (cost-per-delivery, route efficiency, driver utilization) become available. Stop time accuracy affects forecasting and capacity planning." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec describes single-driver-per-zone behavior but does not address the multi-driver case, which is the norm in real logistics operations. This is a critical ambiguity — the entire assignment model changes depending on whether zones have one or many drivers. Additionally, deviation detection criteria are undefined, the notification deduplication strategy on recalculation is unspecified, and shift-end delivery handoff is not mentioned. These gaps affect core invariants.",
    "high_confidence_areas": [
      "Vehicle class enforcement (BR-5) — clear, unambiguous, and physically grounded",
      "Recalculation triggers — three triggers are explicitly enumerated",
      "Stop time default and override mechanism — clear policy with explicit override path",
      "Zone scoping of deliveries to drivers — clearly stated"
    ],
    "low_confidence_areas": [
      "Multi-driver zone behavior — spec is silent on how deliveries are distributed among multiple drivers in the same zone",
      "Deviation detection criteria — what constitutes a 'manual deviation' is undefined (GPS drift? skipped stop? distance threshold?)",
      "Notification behavior on recalculation — no guidance on deduplication, updated ETAs, or notification fatigue",
      "Shift lifecycle — no mention of what happens to route deliveries when a shift ends, or mid-shift breaks",
      "Recalculation concurrency — no guidance on handling rapid successive triggers"
    ],
    "assumptions": [
      "A zone can have multiple active drivers simultaneously (standard in logistics)",
      "Route optimization considers both distance and time, not just one factor",
      "Vehicle class compatibility is a strict hierarchy or matrix, not a simple equality check",
      "Deviation detection is based on the driver visiting stops out of sequence, not pure GPS tracking",
      "Notifications are push notifications to customers, not internal system events",
      "A driver operates in exactly one zone per shift (zone is not dynamic mid-shift)"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not address multi-driver zones. When multiple drivers are active in the same zone and a new delivery arrives, how is the delivery assigned to a specific driver? This fundamentally changes the assignment model — single-driver zones use simple 'add to route,' while multi-driver zones require a load-balancing or proximity-based assignment strategy.",
      "affected_stakeholders": ["Drivers", "Dispatch / Fleet Management", "Operations Team"],
      "options": [
        "A: Nearest-driver assignment — assign to the driver whose current position is closest to the new delivery",
        "B: Least-loaded assignment — assign to the driver with the fewest remaining stops",
        "C: Optimizer-decides — run a global zone optimization across all drivers and reassign optimally",
        "D: Dispatch-manual — surface unassigned deliveries for manual dispatch decision"
      ],
      "recommendation": "Option C (optimizer-decides) is the most correct for an 'optimized route' feature, but it is computationally expensive and means recalculating ALL drivers' routes in the zone. Recommend starting with Option B (least-loaded) with a path to Option C, and get explicit product guidance."
    },
    {
      "type": "ambiguity",
      "description": "Deviation detection is undefined. 'Driver manually deviates from the suggested route' could mean: (a) driver visits stops out of order, (b) driver's GPS position diverges from the planned path by X meters, or (c) driver explicitly signals deviation. Each has very different implementation complexity, false-positive rates, and driver experience implications.",
      "affected_stakeholders": ["Drivers", "Operations Team"],
      "options": [
        "A: Stop-sequence based — deviation is detected when a driver completes a stop that is not the next planned stop",
        "B: GPS-geofence based — deviation is detected when the driver is more than X meters from the planned route for Y minutes",
        "C: Hybrid — sequence-based for confirmed deviations, GPS-based for mid-segment rerouting"
      ],
      "recommendation": "Option A (stop-sequence based) is simplest, most reliable, and avoids GPS noise issues. GPS-based detection adds significant complexity and false-positive risk. Recommend Option A for v1."
    },
    {
      "type": "missing_context",
      "description": "The spec does not define shift-end behavior. When a driver's shift ends, what happens to undelivered stops on their route? This directly affects delivery SLAs and customer notifications. Unaddressed, this creates orphaned deliveries.",
      "affected_stakeholders": ["Customers", "Dispatch / Fleet Management", "Drivers"],
      "options": [
        "A: Auto-reassign remaining deliveries to other active drivers in the zone",
        "B: Return remaining deliveries to the unassigned pool and wait for next shift or manual dispatch",
        "C: Allow shift extension if deliveries remain (with driver consent)"
      ],
      "recommendation": "Option B is safest — return to pool. Option A risks overloading remaining drivers. Need product team decision."
    },
    {
      "type": "ambiguity",
      "description": "Customer notification deduplication on recalculation is unspecified. If a delivery enters the next-3 window, the customer is notified. If recalculation pushes it out and then back in, does the customer get notified again? Recalculation can happen frequently — this could cause notification spam.",
      "affected_stakeholders": ["Customers"],
      "options": [
        "A: Notify once per delivery, ever — customer gets one notification regardless of route changes",
        "B: Notify once per route version — each recalculation resets the notification window",
        "C: Notify on entry to window, and send an update only if ETA changes by more than X minutes"
      ],
      "recommendation": "Option C balances accuracy with notification fatigue. Option A is too coarse (ETA could change significantly). Option B creates spam. Need product/CX team input."
    }
  ],

  "rejection_reasons": []
}

